"""Frozen declarative inventory for the classical-computation branch.

These records name the exact generated-finite kernels to be forced.  They do
not import conventional theorems as premises.  Familiar terms are retained only
as downstream correspondence labels after each result is sealed.
"""

from __future__ import annotations

from dataclasses import dataclass


@dataclass(frozen=True)
class Topic:
    slug: str
    title: str
    subject: str
    components: str
    limitations: str
    correspondence: tuple[str, ...]


def T(slug: str, title: str, subject: str, components: str, limitations: str, *correspondence: str) -> Topic:
    return Topic(slug, title, subject, components, limitations, tuple(correspondence))


