EXPECTED_GROUP_COUNTS = {
    "formal_computation": 12,
    "computability": 10,
    "complexity": 13,
    "algorithms": 14,
    "semantics": 12,
    "distributed_computation": 12,
    "cryptography_security": 13,
    "learning_intelligence": 14,
    "scientific_computation": 13,
}


def validate_topic_inventory() -> None:
    if tuple(GROUP_TOPICS) != tuple(EXPECTED_GROUP_COUNTS):
        raise ValueError("classical-computation group order differs from the frozen inventory")
    for group, expected in EXPECTED_GROUP_COUNTS.items():
        topics = GROUP_TOPICS[group]
        if len(topics) != expected:
            raise ValueError(f"{group} must contain exactly {expected} obligations")
        slugs = tuple(topic.slug for topic in topics)
        if len(set(slugs)) != len(slugs):
            raise ValueError(f"{group} contains duplicate topic slugs")
        if any(not topic.components or not topic.limitations or not topic.correspondence for topic in topics):
            raise ValueError(f"{group} contains an incomplete topic declaration")


validate_topic_inventory()
